// Create sample articles for testing
const sampleArticles = [
  {
    source: 'Dev.to',
    title: 'How to Write Better Tests for Your CI/CD Pipeline',
    url: 'https://dev.to/example/how-to-write-better-tests',
    content: 'A comprehensive guide to testing practices in continuous integration. Covers unit tests, integration tests, and end-to-end testing strategies for modern CI/CD pipelines.',
    tags: ['Python', 'Testing', 'CI/CD', 'GitHub Actions'],
    published_at: '2026-07-12T14:30:00Z',
    score: 87
  },
  {
    source: 'Hacker News',
    title: 'Vitest 2.1 reaches feature parity with Jest on CommonJS',
    url: 'https://example.com/vitest-2-1-cjs',
    content: 'After two years of gradual porting, the last CommonJS-only Jest features now work in Vitest, removing a barrier to migration for legacy monorepos.',
    tags: ['vitest', 'jest', 'testing'],
    published_at: '2026-07-12T16:00:00Z',
    score: 92
  },
  {
    source: 'Reddit',
    title: 'Prompt Injection Patterns in LLM-Based QA Agents',
    url: 'https://example.com/llm-qa-injection',
    content: 'Security researchers document four common injection vectors in agent-based testing tools when using untrusted test data, with mitigations for each.',
    tags: ['security', 'llm', 'testing'],
    published_at: '2026-07-13T10:30:00Z',
    score: 78
  }
];

return sampleArticles.map(article => ({ json: article }));

// Normalize title for deduplication
function normalizeTitle(title) {
  return title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9-]/g, '-')
    .replace(/-+/g, '-')
    .replace(/-$/, '');
}

// Infer category
function inferCategory(article) {
  const text = `${article.title || ''} ${article.content || ''}`.toLowerCase();

  if (['test', 'testing', 'qa', 'automation'].some(w => text.includes(w))) {
    return 'test-automation';
  }
  if (['ai', 'llm', 'gpt', 'agent', 'prompt'].some(w => text.includes(w))) {
    return 'ai';
  }
  if (['architecture', 'deploy', 'performance', 'scaling'].some(w => text.includes(w))) {
    return 'engineering';
  }
  if (['tool', 'script', 'library', 'framework'].some(w => text.includes(w))) {
    return 'tooling';
  }

  return 'qa-practice';
}

// Generate ID
function generateId() {
  return 'article-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
}

const article = $json;

return {
  json: {
    ...article,
    id: article.id || generateId(),
    title: article.title || 'Untitled',
    summary: (article.content || '').substring(0, 1000),
    url: article.url || '',
    source: article.source || 'Unknown',
    category: article.category || inferCategory(article),
    publishedAt: article.published_at || new Date().toISOString(),
    tags: Array.isArray(article.tags) ? article.tags.join(',') : (article.tags || ''),
    addedAt: new Date().toISOString(),
    score: article.score || 50,
    seenCount: 1,
    dedupKey: (article.source || 'Unknown') + '|' + normalizeTitle(article.title || 'untitled')
  }
};

// Transform article for export
const article = $json.json || $json;
const tags = typeof article.tags === 'string' 
  ? article.tags.split(',').map(t => t.trim()).filter(t => t)
  : (Array.isArray(article.tags) ? article.tags : []);

return {
  json: {
    id: article.id,
    title: article.title,
    summary: article.summary,
    url: article.url,
    source: article.source,
    category: article.category || 'qa-practice',
    publishedAt: article.publishedAt,
    tags: tags
  }
};

// Build export object
const articles = $input.all().map(item => item.json);

const today = new Date();
const dateStr = today.toISOString().split('T')[0];
const updatedAt = today.toISOString();

return [{
  json: {
    date: dateStr,
    updatedAt: updatedAt,
    articles: articles
  }
}];

// Summarize test results
const output = $input.all().map(item => item.json)[0];
const exportPath = process.env.EXPORT_FILE_PATH || '/qa-news/public/latest.json';

return [{
  json: {
    test_status: 'COMPLETE',
    timestamp: new Date().toISOString(),
    articles_inserted: 3,
    articles_in_db: '$json("verify-articles").length',
    export_file: exportPath,
    export_data: {
      date: output.date,
      updatedAt: output.updatedAt,
      article_count: output.articles.length
    }
  }
}];
